def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    # Check if slide 8 exists and was modified
    slide_8_modified = False
    for old_slide, new_slide in ppt_diff.modified_slides:
        if old_slide.slide_number == 8 or new_slide.slide_number == 8:
            slide_8_modified = True
            break

    if not slide_8_modified:
        return "Slide 8 was not modified", 0.0

    # Load the modified presentation to check layout
    prs = Presentation(modified_ppt_path)

    if len(prs.slides) < 8:
        return "Slide 8 does not exist in the presentation", 0.0

    slide = prs.slides[7]  # 0-indexed
    layout_name = slide.slide_layout.name.lower()

    # Check if it's a comparison or two-column layout
    comparison_keywords = ['comparison', 'two', 'column', 'content']
    is_comparison_layout = any(keyword in layout_name for keyword in comparison_keywords)

    if is_comparison_layout:
        return f"Slide 8 layout changed to: {slide.slide_layout.name}", 1.0
    else:
        return f"Slide 8 layout is '{slide.slide_layout.name}' which doesn't appear to be a two-column comparison layout", 0.3

def compute_score() -> tuple[str, float]:
    # Use VLM to check whether slide 8 contains headers labeled 'Adults' and 'Children'
    slide_8_image = None
    for s in modified_ppt_screenshots:
        try:
            if getattr(s, 'slide_number', None) == 8:
                slide_8_image = s.image_path
                break
        except Exception:
            continue
    if not slide_8_image:
        return "Slide 8 screenshot not found.", 0.0

    prompt = (
        "Look at slide 8. Are there column headers labeled exactly 'Adults' and 'Children'?\n"
        "Respond YES if both headers are present, PARTIAL if only one is present, or NONE if neither is present.\n"
        "Ignore case and minor styling differences; focus on the presence of the headers."
    )
    try:
        response = vlm_call(images=[slide_8_image], prompt=prompt, temperature=0.1)
        resp = str(response).strip().upper()
        if resp.startswith('YES'):
            return response, 1.0
        elif 'PARTIAL' in resp:
            return response, 0.5
        elif resp.startswith('NONE') or resp.startswith('NO'):
            return response, 0.0
        else:
            return f"Unclear VLM response: {response}", 0.0
    except Exception as e:
        return f"Error during VLM check: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    # Check for modifications to slides other than slide 8
    other_slides_modified = []

    for old_slide, new_slide in ppt_diff.modified_slides:
        if old_slide.slide_number != 8 and new_slide.slide_number != 8:
            other_slides_modified.append(old_slide.slide_number)

    # Check for added/removed slides
    slides_added = len(ppt_diff.added_slides)
    slides_removed = len(ppt_diff.removed_slides)

    if not other_slides_modified and slides_added == 0 and slides_removed == 0:
        return "No extraneous changes to other slides", 1.0
    else:
        issues = []
        if other_slides_modified:
            issues.append(f"Modified slides: {other_slides_modified}")
        if slides_added > 0:
            issues.append(f"Added {slides_added} slides")
        if slides_removed > 0:
            issues.append(f"Removed {slides_removed} slides")

        return f"Extraneous changes detected: {', '.join(issues)}", 0.0

def compute_score() -> tuple[str, float]:
    # Check for animation/transition changes
    animations_added = len(ppt_diff.added_animations)
    animations_removed = len(ppt_diff.removed_animations)
    animations_modified = len(ppt_diff.modified_animations)

    transitions_added = len(ppt_diff.added_transitions)
    transitions_removed = len(ppt_diff.removed_transitions)
    transitions_modified = len(ppt_diff.modified_transitions)

    total_changes = (animations_added + animations_removed + animations_modified + 
                    transitions_added + transitions_removed + transitions_modified)

    if total_changes == 0:
        return "No unnecessary animation or transition changes", 1.0
    else:
        changes = []
        if animations_added > 0:
            changes.append(f"{animations_added} animations added")
        if animations_removed > 0:
            changes.append(f"{animations_removed} animations removed")
        if animations_modified > 0:
            changes.append(f"{animations_modified} animations modified")
        if transitions_added > 0:
            changes.append(f"{transitions_added} transitions added")
        if transitions_removed > 0:
            changes.append(f"{transitions_removed} transitions removed")
        if transitions_modified > 0:
            changes.append(f"{transitions_modified} transitions modified")

        return f"Unnecessary animation/transition changes: {', '.join(changes)}", 0.5
